INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, "", "", 11, 112631, "", "", "", 1010024, 1, "こういうのってさ\n上がどうなってるか\n見てみたいよね！");
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", "", "", 91, 0, "", "", "", 1010025, 1, "");
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, "", "", 11, 112531, "", "", "", 1010026, 1, "確かにね…それに\nこうなった理由も\n分かるかも");
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", "", "", 91, 0, "", "", "", 1010027, 1, "");
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, "", "", 11, 106031, "", "", "", 1010028, 1, "ま、興味はあるし\n付き合ってあげるわ");
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", "", "", 91, 0, "", "", "", 1010029, 1, "");
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, "", "", 11, 112431, "", "", "", 1010030, 1, "はい♪みなさんで\n頂上を目指して\n頑張りましょう！");
